program lipdecide;

{$mode objfpc}{$H+}

uses
  SysUtils, Math;

const
  PI_CONST = 3.1415926535;

type
  POINTRANGE = 1..100;
  LICRANGE = 1..15;
  CONNECTORS = (NOTUSED, ORR, ANDD);
  COORDINATE = array[POINTRANGE] of real;
  CMATRIX = array[LICRANGE, LICRANGE] of CONNECTORS;
  BMATRIX = array[LICRANGE, LICRANGE] of boolean;
  VECTOR = array[LICRANGE] of boolean;
  COMPTYPE = (LT, EQ, GT);

  PARAMREC = record
    LENGTH1: real;
    RADIUS1: real;
    EPSILON: real;
    AREA1: real;
    Q_PTS: integer;
    QUADS: integer;
    DIST: real;
    N_PTS: integer;
    K_PTS: integer;
    A_PTS: integer;
    B_PTS: integer;
    C_PTS: integer;
    D_PTS: integer;
    E_PTS: integer;
    F_PTS: integer;
    G_PTS: integer;
    LENGTH2: real;
    RADIUS2: real;
    AREA2: real;
  end;

var
  X: COORDINATE;
  Y: COORDINATE;
  NUMPOINTS: integer;
  PARAMETERS: PARAMREC;
  LCM: CMATRIX;
  PUM: BMATRIX;
  CMV: VECTOR;
  FUV: VECTOR;
  LAUNCH: boolean;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  scale, eps, diff: real;
begin
  scale := Abs(A);
  if Abs(B) > scale then
    scale := Abs(B);
  if scale = 0.0 then
  begin
    REALCOMPARE := EQ;
    Exit;
  end;

  eps := 0.5e-5 * scale;
  diff := A - B;
  if diff > eps then
    REALCOMPARE := GT
  else if diff < -eps then
    REALCOMPARE := LT
  else
    REALCOMPARE := EQ;
end;

function RealGT(A, B: real): boolean;
begin
  RealGT := REALCOMPARE(A, B) = GT;
end;

function RealLT(A, B: real): boolean;
begin
  RealLT := REALCOMPARE(A, B) = LT;
end;

function RealGE(A, B: real): boolean;
begin
  RealGE := REALCOMPARE(A, B) <> LT;
end;

function RealLE(A, B: real): boolean;
begin
  RealLE := REALCOMPARE(A, B) <> GT;
end;

function SamePoint(I, J: integer): boolean;
begin
  SamePoint := (REALCOMPARE(X[I], X[J]) = EQ) and (REALCOMPARE(Y[I], Y[J]) = EQ);
end;

function DistPoints(I, J: integer): real;
var
  DX, DY: real;
begin
  DX := X[I] - X[J];
  DY := Y[I] - Y[J];
  DistPoints := Sqrt(DX * DX + DY * DY);
end;

function DistToCenter(PX, PY, CX, CY: real): real;
var
  DX, DY: real;
begin
  DX := PX - CX;
  DY := PY - CY;
  DistToCenter := Sqrt(DX * DX + DY * DY);
end;

function QuadrantOfPoint(PX, PY: real): integer;
begin
  if RealGE(PX, 0.0) and RealGE(PY, 0.0) then
    QuadrantOfPoint := 1
  else if RealLT(PX, 0.0) and RealGE(PY, 0.0) then
    QuadrantOfPoint := 2
  else if RealLE(PX, 0.0) and RealLT(PY, 0.0) then
    QuadrantOfPoint := 3
  else
    QuadrantOfPoint := 4;
end;

function TriangleArea(I, J, K: integer): real;
var
  Cross: real;
begin
  Cross := (X[J] - X[I]) * (Y[K] - Y[I]) - (X[K] - X[I]) * (Y[J] - Y[I]);
  TriangleArea := Abs(Cross) / 2.0;
end;

function AngleCondition(I, J, K: integer): boolean;
var
  V1X, V1Y, V2X, V2Y, N1, N2, DotP, CosAng, Ang, LowB, HighB: real;
begin
  if SamePoint(I, J) or SamePoint(K, J) then
  begin
    AngleCondition := false;
    Exit;
  end;

  V1X := X[I] - X[J];
  V1Y := Y[I] - Y[J];
  V2X := X[K] - X[J];
  V2Y := Y[K] - Y[J];
  N1 := Sqrt(V1X * V1X + V1Y * V1Y);
  N2 := Sqrt(V2X * V2X + V2Y * V2Y);

  DotP := V1X * V2X + V1Y * V2Y;
  CosAng := DotP / (N1 * N2);
  if CosAng > 1.0 then
    CosAng := 1.0
  else if CosAng < -1.0 then
    CosAng := -1.0;

  Ang := ArcCos(CosAng);
  LowB := PI_CONST - PARAMETERS.EPSILON;
  HighB := PI_CONST + PARAMETERS.EPSILON;
  AngleCondition := RealLT(Ang, LowB) or RealGT(Ang, HighB);
end;

function ExistsCircleRadiusR(I, J, K: integer; R: real): boolean;
var
  MinR: real;
  CX, CY, CandR, D: real;

  procedure ConsiderDiameter(P1, P2, P3: integer);
  var
    MCX, MCY, MR, D3: real;
  begin
    MCX := (X[P1] + X[P2]) / 2.0;
    MCY := (Y[P1] + Y[P2]) / 2.0;
    MR := DistPoints(P1, P2) / 2.0;
    D3 := DistToCenter(X[P3], Y[P3], MCX, MCY);
    if RealLE(D3, MR) and RealLT(MR, MinR) then
      MinR := MR;
  end;

begin
  MinR := 1.0E30;

  ConsiderDiameter(I, J, K);
  ConsiderDiameter(I, K, J);
  ConsiderDiameter(J, K, I);

  D := 2.0 * (X[I] * (Y[J] - Y[K]) + X[J] * (Y[K] - Y[I]) + X[K] * (Y[I] - Y[J]));
  if REALCOMPARE(D, 0.0) <> EQ then
  begin
    CX := ((X[I] * X[I] + Y[I] * Y[I]) * (Y[J] - Y[K]) +
           (X[J] * X[J] + Y[J] * Y[J]) * (Y[K] - Y[I]) +
           (X[K] * X[K] + Y[K] * Y[K]) * (Y[I] - Y[J])) / D;
    CY := ((X[I] * X[I] + Y[I] * Y[I]) * (X[K] - X[J]) +
           (X[J] * X[J] + Y[J] * Y[J]) * (X[I] - X[K]) +
           (X[K] * X[K] + Y[K] * Y[K]) * (X[J] - X[I])) / D;
    CandR := DistToCenter(X[I], Y[I], CX, CY);
    if RealLT(CandR, MinR) then
      MinR := CandR;
  end;

  ExistsCircleRadiusR := RealLE(MinR, R);
end;

function LIC1: boolean;
var
  I: integer;
begin
  LIC1 := false;
  for I := 1 to NUMPOINTS - 1 do
    if RealGT(DistPoints(I, I + 1), PARAMETERS.LENGTH1) then
    begin
      LIC1 := true;
      Exit;
    end;
end;

function LIC2: boolean;
var
  I: integer;
begin
  LIC2 := false;
  for I := 1 to NUMPOINTS - 2 do
    if not ExistsCircleRadiusR(I, I + 1, I + 2, PARAMETERS.RADIUS1) then
    begin
      LIC2 := true;
      Exit;
    end;
end;

function LIC3: boolean;
var
  I: integer;
begin
  LIC3 := false;
  for I := 1 to NUMPOINTS - 2 do
    if AngleCondition(I, I + 1, I + 2) then
    begin
      LIC3 := true;
      Exit;
    end;
end;

function LIC4: boolean;
var
  I: integer;
begin
  LIC4 := false;
  for I := 1 to NUMPOINTS - 2 do
    if RealGT(TriangleArea(I, I + 1, I + 2), PARAMETERS.AREA1) then
    begin
      LIC4 := true;
      Exit;
    end;
end;

function LIC5: boolean;
var
  I, J, Q, CountQ: integer;
  Seen: array[1..4] of boolean;
begin
  LIC5 := false;
  for I := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    for Q := 1 to 4 do
      Seen[Q] := false;
    for J := I to I + PARAMETERS.Q_PTS - 1 do
    begin
      Q := QuadrantOfPoint(X[J], Y[J]);
      Seen[Q] := true;
    end;
    CountQ := 0;
    for Q := 1 to 4 do
      if Seen[Q] then
        Inc(CountQ);
    if CountQ > PARAMETERS.QUADS then
    begin
      LIC5 := true;
      Exit;
    end;
  end;
end;

function LIC6: boolean;
var
  I: integer;
begin
  LIC6 := false;
  for I := 1 to NUMPOINTS - 1 do
    if RealLT(X[I + 1] - X[I], 0.0) then
    begin
      LIC6 := true;
      Exit;
    end;
end;

function DistPointToLine(I, A, B: integer): real;
var
  Num, Den: real;
begin
  Num := Abs((Y[B] - Y[A]) * X[I] - (X[B] - X[A]) * Y[I] + X[B] * Y[A] - Y[B] * X[A]);
  Den := DistPoints(A, B);
  DistPointToLine := Num / Den;
end;

function LIC7: boolean;
var
  StartIdx, A, B, K: integer;
  D: real;
begin
  LIC7 := false;
  if NUMPOINTS < 3 then
    Exit;

  for StartIdx := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    A := StartIdx;
    B := StartIdx + PARAMETERS.N_PTS - 1;
    if SamePoint(A, B) then
    begin
      for K := A + 1 to B - 1 do
      begin
        D := DistPoints(A, K);
        if RealGT(D, PARAMETERS.DIST) then
        begin
          LIC7 := true;
          Exit;
        end;
      end;
    end
    else
    begin
      for K := A + 1 to B - 1 do
      begin
        D := DistPointToLine(K, A, B);
        if RealGT(D, PARAMETERS.DIST) then
        begin
          LIC7 := true;
          Exit;
        end;
      end;
    end;
  end;
end;

function LIC8: boolean;
var
  I, J: integer;
begin
  LIC8 := false;
  if NUMPOINTS < 3 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    if RealGT(DistPoints(I, J), PARAMETERS.LENGTH1) then
    begin
      LIC8 := true;
      Exit;
    end;
  end;
end;

function LIC9: boolean;
var
  I, J, K: integer;
begin
  LIC9 := false;
  if NUMPOINTS < 5 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;
    if not ExistsCircleRadiusR(I, J, K, PARAMETERS.RADIUS1) then
    begin
      LIC9 := true;
      Exit;
    end;
  end;
end;

function LIC10: boolean;
var
  I, J, K: integer;
begin
  LIC10 := false;
  if NUMPOINTS < 5 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    J := I + PARAMETERS.C_PTS + 1;
    K := J + PARAMETERS.D_PTS + 1;
    if AngleCondition(I, J, K) then
    begin
      LIC10 := true;
      Exit;
    end;
  end;
end;

function LIC11: boolean;
var
  I, J, K: integer;
begin
  LIC11 := false;
  if NUMPOINTS < 5 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    if RealGT(TriangleArea(I, J, K), PARAMETERS.AREA1) then
    begin
      LIC11 := true;
      Exit;
    end;
  end;
end;

function LIC12: boolean;
var
  I, J: integer;
begin
  LIC12 := false;
  if NUMPOINTS < 3 then
    Exit;

  for I := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    J := I + PARAMETERS.G_PTS + 1;
    if RealLT(X[J] - X[I], 0.0) then
    begin
      LIC12 := true;
      Exit;
    end;
  end;
end;

function LIC13: boolean;
var
  I, J: integer;
  HasGT, HasLT: boolean;
  D: real;
begin
  LIC13 := false;
  if NUMPOINTS < 3 then
    Exit;

  HasGT := false;
  HasLT := false;
  for I := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    J := I + PARAMETERS.K_PTS + 1;
    D := DistPoints(I, J);
    if RealGT(D, PARAMETERS.LENGTH1) then
      HasGT := true;
    if RealLT(D, PARAMETERS.LENGTH2) then
      HasLT := true;
    if HasGT and HasLT then
    begin
      LIC13 := true;
      Exit;
    end;
  end;
end;

function LIC14: boolean;
var
  I, J, K: integer;
  HasNotInR1, HasInR2: boolean;
begin
  LIC14 := false;
  if NUMPOINTS < 5 then
    Exit;

  HasNotInR1 := false;
  HasInR2 := false;
  for I := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    J := I + PARAMETERS.A_PTS + 1;
    K := J + PARAMETERS.B_PTS + 1;
    if not ExistsCircleRadiusR(I, J, K, PARAMETERS.RADIUS1) then
      HasNotInR1 := true;
    if ExistsCircleRadiusR(I, J, K, PARAMETERS.RADIUS2) then
      HasInR2 := true;
    if HasNotInR1 and HasInR2 then
    begin
      LIC14 := true;
      Exit;
    end;
  end;
end;

function LIC15: boolean;
var
  I, J, K: integer;
  HasGT, HasLT: boolean;
  A: real;
begin
  LIC15 := false;
  if NUMPOINTS < 5 then
    Exit;

  HasGT := false;
  HasLT := false;
  for I := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    J := I + PARAMETERS.E_PTS + 1;
    K := J + PARAMETERS.F_PTS + 1;
    A := TriangleArea(I, J, K);
    if RealGT(A, PARAMETERS.AREA1) then
      HasGT := true;
    if RealLT(A, PARAMETERS.AREA2) then
      HasLT := true;
    if HasGT and HasLT then
    begin
      LIC15 := true;
      Exit;
    end;
  end;
end;

procedure DECIDE;
var
  I, J: integer;
  RowAllTrue: boolean;
begin
  CMV[1] := LIC1;
  CMV[2] := LIC2;
  CMV[3] := LIC3;
  CMV[4] := LIC4;
  CMV[5] := LIC5;
  CMV[6] := LIC6;
  CMV[7] := LIC7;
  CMV[8] := LIC8;
  CMV[9] := LIC9;
  CMV[10] := LIC10;
  CMV[11] := LIC11;
  CMV[12] := LIC12;
  CMV[13] := LIC13;
  CMV[14] := LIC14;
  CMV[15] := LIC15;

  for I := 1 to 15 do
    for J := 1 to 15 do
      if I <> J then
      begin
        case LCM[I, J] of
          NOTUSED: PUM[I, J] := true;
          ORR: PUM[I, J] := CMV[I] or CMV[J];
          ANDD: PUM[I, J] := CMV[I] and CMV[J];
        end;
      end;

  for I := 1 to 15 do
  begin
    if not PUM[I, I] then
      FUV[I] := true
    else
    begin
      RowAllTrue := true;
      for J := 1 to 15 do
        if not PUM[I, J] then
        begin
          RowAllTrue := false;
          Break;
        end;
      FUV[I] := RowAllTrue;
    end;
  end;

  LAUNCH := true;
  for I := 1 to 15 do
    if not FUV[I] then
    begin
      LAUNCH := false;
      Exit;
    end;
end;

function ConnectorFromString(const S: string): CONNECTORS;
begin
  if S = 'ANDD' then
    ConnectorFromString := ANDD
  else if S = 'ORR' then
    ConnectorFromString := ORR
  else
    ConnectorFromString := NOTUSED;
end;

procedure ParseInput(const S: string);
var
  P: integer;

  procedure SkipWS;
  begin
    while (P <= Length(S)) and (S[P] <= ' ') do
      Inc(P);
  end;

  procedure ExpectChar(C: char);
  begin
    SkipWS;
    if (P > Length(S)) or (S[P] <> C) then
      Halt(1);
    Inc(P);
  end;

  function PeekChar: char;
  begin
    SkipWS;
    if P > Length(S) then
      PeekChar := #0
    else
      PeekChar := S[P];
  end;

  function ParseString: string;
  var
    Ch: char;
    HexVal: string;
    CodePoint: integer;
  begin
    Result := '';
    SkipWS;
    if (P > Length(S)) or (S[P] <> '"') then
      Halt(1);
    Inc(P);
    while P <= Length(S) do
    begin
      Ch := S[P];
      Inc(P);
      if Ch = '"' then
        Exit;
      if Ch = '\' then
      begin
        if P > Length(S) then
          Halt(1);
        Ch := S[P];
        Inc(P);
        case Ch of
          '"': Result := Result + '"';
          '\': Result := Result + '\';
          '/': Result := Result + '/';
          'b': Result := Result + #8;
          'f': Result := Result + #12;
          'n': Result := Result + #10;
          'r': Result := Result + #13;
          't': Result := Result + #9;
          'u':
            begin
              if P + 3 > Length(S) then
                Halt(1);
              HexVal := Copy(S, P, 4);
              Inc(P, 4);
              CodePoint := StrToInt('$' + HexVal);
              if CodePoint <= 255 then
                Result := Result + Chr(CodePoint)
              else
                Result := Result + '?';
            end;
        else
          Halt(1);
        end;
      end
      else
        Result := Result + Ch;
    end;
    Halt(1);
  end;

  function ParseNumber: real;
  var
    StartPos: integer;
    NumStr: string;
  begin
    SkipWS;
    StartPos := P;
    if (P <= Length(S)) and ((S[P] = '-') or (S[P] = '+')) then
      Inc(P);
    while (P <= Length(S)) and (S[P] in ['0'..'9']) do
      Inc(P);
    if (P <= Length(S)) and (S[P] = '.') then
    begin
      Inc(P);
      while (P <= Length(S)) and (S[P] in ['0'..'9']) do
        Inc(P);
    end;
    if (P <= Length(S)) and ((S[P] = 'e') or (S[P] = 'E')) then
    begin
      Inc(P);
      if (P <= Length(S)) and ((S[P] = '-') or (S[P] = '+')) then
        Inc(P);
      while (P <= Length(S)) and (S[P] in ['0'..'9']) do
        Inc(P);
    end;
    NumStr := Copy(S, StartPos, P - StartPos);
    if NumStr = '' then
      Halt(1);
    Result := StrToFloat(NumStr, DefaultFormatSettings);
  end;

  function ParseInteger: integer;
  begin
    ParseInteger := Round(ParseNumber);
  end;

  function ParseBoolean: boolean;
  begin
    SkipWS;
    if Copy(S, P, 4) = 'true' then
    begin
      Inc(P, 4);
      ParseBoolean := true;
    end
    else if Copy(S, P, 5) = 'false' then
    begin
      Inc(P, 5);
      ParseBoolean := false;
    end
    else
      Halt(1);
  end;

  procedure SkipValue; forward;

  procedure SkipObject;
  var
    Key: string;
  begin
    ExpectChar('{');
    SkipWS;
    if PeekChar = '}' then
    begin
      Inc(P);
      Exit;
    end;
    while true do
    begin
      Key := ParseString;
      if Key = '' then begin end;
      ExpectChar(':');
      SkipValue;
      SkipWS;
      if PeekChar = '}' then
      begin
        Inc(P);
        Exit;
      end;
      ExpectChar(',');
    end;
  end;

  procedure SkipArray;
  begin
    ExpectChar('[');
    SkipWS;
    if PeekChar = ']' then
    begin
      Inc(P);
      Exit;
    end;
    while true do
    begin
      SkipValue;
      SkipWS;
      if PeekChar = ']' then
      begin
        Inc(P);
        Exit;
      end;
      ExpectChar(',');
    end;
  end;

  procedure SkipValue;
  var
    C: char;
  begin
    SkipWS;
    C := PeekChar;
    case C of
      '{': SkipObject;
      '[': SkipArray;
      '"': begin ParseString; end;
      't', 'f': begin ParseBoolean; end;
      'n':
        begin
          if Copy(S, P, 4) <> 'null' then
            Halt(1);
          Inc(P, 4);
        end;
    else
      begin
        ParseNumber;
      end;
    end;
  end;

  procedure ParseNumberArray(var Arr: COORDINATE);
  var
    Idx: integer;
  begin
    ExpectChar('[');
    Idx := 1;
    SkipWS;
    if PeekChar = ']' then
    begin
      Inc(P);
      Exit;
    end;
    while true do
    begin
      Arr[Idx] := ParseNumber;
      Inc(Idx);
      SkipWS;
      if PeekChar = ']' then
      begin
        Inc(P);
        Exit;
      end;
      ExpectChar(',');
    end;
  end;

  procedure ParseDiag;
  var
    I: integer;
  begin
    ExpectChar('[');
    for I := 1 to 15 do
    begin
      PUM[I, I] := ParseBoolean;
      if I < 15 then
        ExpectChar(',');
    end;
    ExpectChar(']');
  end;

  procedure ParseLCMMatrix;
  var
    I, J: integer;
    CS: string;
  begin
    ExpectChar('[');
    for I := 1 to 15 do
    begin
      ExpectChar('[');
      for J := 1 to 15 do
      begin
        CS := ParseString;
        LCM[I, J] := ConnectorFromString(CS);
        if J < 15 then
          ExpectChar(',');
      end;
      ExpectChar(']');
      if I < 15 then
        ExpectChar(',');
    end;
    ExpectChar(']');
  end;

  procedure ParseParameters;
  var
    Key: string;
  begin
    ExpectChar('{');
    SkipWS;
    if PeekChar = '}' then
    begin
      Inc(P);
      Exit;
    end;
    while true do
    begin
      Key := ParseString;
      ExpectChar(':');
      if Key = 'LENGTH1' then PARAMETERS.LENGTH1 := ParseNumber
      else if Key = 'RADIUS1' then PARAMETERS.RADIUS1 := ParseNumber
      else if Key = 'EPSILON' then PARAMETERS.EPSILON := ParseNumber
      else if Key = 'AREA1' then PARAMETERS.AREA1 := ParseNumber
      else if Key = 'Q_PTS' then PARAMETERS.Q_PTS := ParseInteger
      else if Key = 'QUADS' then PARAMETERS.QUADS := ParseInteger
      else if Key = 'DIST' then PARAMETERS.DIST := ParseNumber
      else if Key = 'N_PTS' then PARAMETERS.N_PTS := ParseInteger
      else if Key = 'K_PTS' then PARAMETERS.K_PTS := ParseInteger
      else if Key = 'A_PTS' then PARAMETERS.A_PTS := ParseInteger
      else if Key = 'B_PTS' then PARAMETERS.B_PTS := ParseInteger
      else if Key = 'C_PTS' then PARAMETERS.C_PTS := ParseInteger
      else if Key = 'D_PTS' then PARAMETERS.D_PTS := ParseInteger
      else if Key = 'E_PTS' then PARAMETERS.E_PTS := ParseInteger
      else if Key = 'F_PTS' then PARAMETERS.F_PTS := ParseInteger
      else if Key = 'G_PTS' then PARAMETERS.G_PTS := ParseInteger
      else if Key = 'LENGTH2' then PARAMETERS.LENGTH2 := ParseNumber
      else if Key = 'RADIUS2' then PARAMETERS.RADIUS2 := ParseNumber
      else if Key = 'AREA2' then PARAMETERS.AREA2 := ParseNumber
      else SkipValue;

      SkipWS;
      if PeekChar = '}' then
      begin
        Inc(P);
        Exit;
      end;
      ExpectChar(',');
    end;
  end;

var
  Key: string;
begin
  DefaultFormatSettings.DecimalSeparator := '.';
  P := 1;
  ExpectChar('{');
  SkipWS;
  if PeekChar = '}' then
    Exit;

  while true do
  begin
    Key := ParseString;
    ExpectChar(':');
    if Key = 'numpoints' then
      NUMPOINTS := ParseInteger
    else if Key = 'x' then
      ParseNumberArray(X)
    else if Key = 'y' then
      ParseNumberArray(Y)
    else if Key = 'parameters' then
      ParseParameters
    else if Key = 'lcm' then
      ParseLCMMatrix
    else if Key = 'pum_diag' then
      ParseDiag
    else
      SkipValue;

    SkipWS;
    if PeekChar = '}' then
    begin
      Inc(P);
      Break;
    end;
    ExpectChar(',');
  end;
end;

procedure WriteBool(B: boolean);
begin
  if B then
    Write('true')
  else
    Write('false');
end;

procedure WriteOutputToStdout;
var
  I, J: integer;
begin
  Write('{"cmv":[');
  for I := 1 to 15 do
  begin
    if I > 1 then
      Write(',');
    WriteBool(CMV[I]);
  end;

  Write('],"pum":[');
  for I := 1 to 15 do
  begin
    if I > 1 then
      Write(',');
    Write('[');
    for J := 1 to 15 do
    begin
      if J > 1 then
        Write(',');
      WriteBool(PUM[I, J]);
    end;
    Write(']');
  end;

  Write('],"fuv":[');
  for I := 1 to 15 do
  begin
    if I > 1 then
      Write(',');
    WriteBool(FUV[I]);
  end;

  Write('],"launch":');
  WriteBool(LAUNCH);
  Write('}');
end;

function ReadAllStdin: string;
var
  Ch: char;
begin
  Result := '';
  while not EOF(Input) do
  begin
    Read(Input, Ch);
    Result := Result + Ch;
  end;
end;

begin
  ParseInput(ReadAllStdin);
  DECIDE;
  WriteOutputToStdout;
end.
